// 조회
scwin.f_Retrieve = async function () {
  // VALIDATE
  if (!(await $c.gus.cfValidate($p, [lc_etdEta, lc_docCargo]))) {
    //validExp 가 yes일때 check
    return;
  }

  // 날짜 범위 확인
  if (ed_etdEtaSt.getValue() != "" || ed_etdEtaEnd.getValue() != "") {
    if (!(await $c.gus.cfIsAfterDate($p, ed_etdEtaSt.getValue(), ed_etdEtaEnd.getValue()))) {
      if (await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_048, new Array("ETD From", "ETD To"))) {
        //@은(는) 보다 작아야 합니다.
        ed_etdEtaSt.focus();
        return false;
      }
    }
  }

  // 날짜 범위 확인
  if (ed_docCargoSt.getValue() != "" || ed_docCargoEnd.getValue() != "") {
    if (!(await $c.gus.cfIsAfterDate($p, ed_docCargoSt.getValue(), ed_docCargoEnd.getValue()))) {
      if (await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_048, new Array("DOC From", "DOC To"))) {
        //@은(는) 보다 작아야 합니다.
        ed_docCargoSt.focus();
        return false;
      }
    }
  }
  let e = await $c.sbm.execute($p, sbm_retrieve);
  if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
    scwin.sbm_retrieve_submitdone(e);
  }
};

// 저장
scwin.f_save = async function () {
  if (ds_master.getModifiedIndex().length == 0) {
    $c.win.alert($p, "변경된 사항이 없습니다.");
    return;
  }
  for (var i = 0; i < ds_master.getRowCount(); i++) {
    if (ds_master.getModifiedIndex().length != 0 && ds_master.getRowStatus(i) == "U") {
      if (ds_master.getCellData(i, "issueYn") == "T" && ds_master.getCellData(i, "hhblno") == "") {
        $c.win.alert($p, "ISSUE 체크는 BL 등록후에 가능합니다.");
        return;
      }
      if (ds_master.getCellData(i, "isfYn") == "T" && ds_master.getCellData(i, "hhblno") == "") {
        $c.win.alert($p, "ISF 체크는 BL 등록후에 가능합니다.");
        return;
      }
      if (ds_master.getCellData(i, "prealertYn") == "T" && ds_master.getCellData(i, "hhblno") == "") {
        $c.win.alert($p, "PRE ALERT 체크는 BL 등록후에 가능합니다.");
        return;
      }
    }
  }
  let saveChk = await $c.win.confirm($p, MSG_CM_CRM_001);
  if (saveChk) {
    // RowPosition 저장
    scwin.f_GetRowPosition();
    let e = await $c.sbm.execute($p, sbm_save);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
      scwin.sbm_save_submitdone(e);
    }
  }
};
