// 그리드 지정
scwin.f_setColumn = function () {
  ds_master.setRowPosition(0);
  gr_master.setFocusedCell(gr_master.getFocusedRowIndex(), "custNm");
};
scwin.fn_myNumFormatter = function (data, type) {
  // 1. 유효성 체크 (빈 값 처리)
  if (data === "" || data === undefined || data === null) return "";

  // 숫자로 변환 (콤마 제거 후 변환)
  var num = parseFloat(data.toString().replace(/,/g, ""));
  if (isNaN(num)) return data;

  // 2. 0 표기 안 함 (decao0 전용)
  if (type === "decao0" && num === 0) return "";

  // 3. 포맷별 분기 처리
  switch (type) {
    // [Fixed 시리즈] 소수점 자릿수 무조건 고정 (#,###.00)
    case "dec0":
      return num.toLocaleString('en-US', {
        minimumFractionDigits: 0,
        maximumFractionDigits: 0
      });
    case "dec1":
      return num.toLocaleString('en-US', {
        minimumFractionDigits: 1,
        maximumFractionDigits: 1
      });
    case "dec2":
      return num.toLocaleString('en-US', {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2
      });
    case "dec3":
      return num.toLocaleString('en-US', {
        minimumFractionDigits: 3,
        maximumFractionDigits: 3
      });
    case "dec4":
      return num.toLocaleString('en-US', {
        minimumFractionDigits: 4,
        maximumFractionDigits: 4
      });

    // [Optional 시리즈] 소수점 있을 때만 표시 (#,###.##)
    case "decao0":
      return num.toLocaleString('en-US', {
        minimumFractionDigits: 0,
        maximumFractionDigits: 0
      });
    case "decao1":
      return num.toLocaleString('en-US', {
        minimumFractionDigits: 0,
        maximumFractionDigits: 1
      });
    case "decao2":
      return num.toLocaleString('en-US', {
        minimumFractionDigits: 0,
        maximumFractionDigits: 2
      });
    case "decao3":
      return num.toLocaleString('en-US', {
        minimumFractionDigits: 0,
        maximumFractionDigits: 3
      });
    case "decao4":
      return num.toLocaleString('en-US', {
        minimumFractionDigits: 0,
        maximumFractionDigits: 4
      });
    default:
      return data;
  }
};

