scwin.gr_master_oncelldblclick = function (rowIndex, columnIndex, columnId) {
  if (rowIndex > -1) {
    var paramObj = {};
    let options = {
      "openAction": "exist"
    };
    var menuName = "";
    var menuUrl = "";
    var menuUrlNm = "";
    if (columnId == "bkNo") {
      paramObj = {
        linkcheck: "1",
        kcomcd: scwin.hd_kcomcd,
        bkno: ds_master.getCellData(rowIndex, "bkNo")
      };
      menuName = "Container Booking";
      menuUrl = "/ui/il/seaout/sobk/se_101_01_01b.xml";
      menuUrlNm = "se_101_01_01b.jsp";
      $c.win.openMenu($p, menuName, menuUrl, menuUrlNm, paramObj, options);
    } else if (columnId == "hhblno" && ds_master.getCellData(rowIndex, "autono") == "DIRECT" && ds_master.getCellData(rowIndex, "hhblno") != "") {
      paramObj = {
        linkcheck: "1",
        kcomcd: scwin.hd_kcomcd,
        blno: ds_master.getCellData(rowIndex, "hhblno"),
        mhno: ds_master.getCellData(rowIndex, "mhno")
      };
      menuName = "Direct B/L";
      menuUrl = "/ui/il/seaout/sobl/se_107_01_01b.xml";
      menuUrlNm = "se_107_01_01b.jsp";
      $c.win.openMenu($p, menuName, menuUrl, menuUrlNm, paramObj, options);
    } else if (columnId == "hhblno" && ds_master.getCellData(rowIndex, "autono") != "DIRECT" && ds_master.getCellData(rowIndex, "hhblno") != "") {
      paramObj = {
        linkcheck: "1",
        kcomcd: scwin.hd_kcomcd,
        blno: ds_master.getCellData(rowIndex, "hhblno"),
        mhno: ds_master.getCellData(rowIndex, "mhno")
      };
      menuName = "Export House B/L";
      menuUrl = "/ui/il/seaout/sobl/se_105_01_01b.xml";
      menuUrlNm = "se_105_01_01b.jsp";
      $c.win.openMenu($p, menuName, menuUrl, menuUrlNm, paramObj, options);
    }
  }
};
