scwin.gr_master_onviewchange = function (info) {
  var colId = info.colId;
  var rowIndex = info.rowIndex;
  var newValue = info.newValue;

  // issueYn 또는 compulsionEndYn 컬럼이 변경되었을 때만 실행
  if (colId == "issueYn" || colId == "compulsionEndYn") {
    // 데이터셋에서 현재 행의 데이터를 가져옴
    const itemObj = ds_master.getRowJSON(rowIndex);

    // ★ 핵심: onviewchange 시점의 최신 변경 값을 itemObj에 미리 반영해 줍니다.
    itemObj[colId] = newValue;
    let bgColor = "";

    // 1. 공통으로 회색(#D5D5D5)이 되는 조건 최우선 처리
    if (itemObj.chargeStatus === '완료' && (itemObj.settleStatus === '완료' || itemObj.settleStatus === '내부거래')) {
      bgColor = '#D5D5D5';
    }
    // 2. issueYn 상태에 따른 분기
    else if (itemObj.issueYn === 'T') {
      if (itemObj.compulsionEndYn === 'T') {
        bgColor = '#D5D5D5';
      } else {
        bgColor = '#D1B2FF';
      }
    }
    // 3. 위 조건에 해당하지 않는 나머지의 기본 컬러 설정
    else {
      if (itemObj.iptYn === '1') {
        bgColor = 'yellow';
      } else {
        bgColor = 'white';
      }
    }

    // --- 색상 적용 루프 ---
    var colCount = gr_master.getColumnCount();
    for (var i = 0; i < colCount; i++) {
      // 인덱스로 컬럼 ID 추출하여 모든 컬럼에 동일한 bgColor 적용
      var targetColId = gr_master.getColumnID(i);
      gr_master.setCellBackgroundColor(rowIndex, targetColId, bgColor);
    }
  }
};

